import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Cyclo Framework","description":"","frontmatter":{},"headers":[],"relativePath":"projects/cyclo-framework.md","filePath":"projects/cyclo-framework.md","lastUpdated":null}'),i={name:"projects/cyclo-framework.md"};function l(n,e,s,c,h,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="cyclo-framework" tabindex="-1">Cyclo Framework <a class="header-anchor" href="#cyclo-framework" aria-label="Permalink to &quot;Cyclo Framework&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Cyclo Framework</strong> is a working name for a <strong>cyclic development</strong> practice: short build–measure–document loops that keep hardware-in-the-loop stacks honest. It is not a product; it is a checklist and folder contract I reuse across projects.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Long integration cycles hide coupling. Tightening the loop surfaces scheduling issues, frame mismatches, and brittle assumptions while they are still cheap to fix.</p><h2 id="technical-scope" tabindex="-1">Technical Scope <a class="header-anchor" href="#technical-scope" aria-label="Permalink to &quot;Technical Scope&quot;">​</a></h2><ul><li>Weekly integration goals sized to fit <strong>two afternoons</strong> of focused bench time</li><li>Standard experiment cards: hypothesis, setup, metrics, outcome, next tweak</li><li>Promotion path from <strong>Tech Log</strong> bullets to <strong>Article</strong> outlines at month end</li></ul><h2 id="what-i-learned" tabindex="-1">What I Learned <a class="header-anchor" href="#what-i-learned" aria-label="Permalink to &quot;What I Learned&quot;">​</a></h2><ul><li>The bottleneck is rarely compiler speed; it is <strong>unclear success criteria</strong> before touching the robot.</li><li>A lightweight schema beats a heavy “process” document when everyone actually fills it in.</li></ul><h2 id="related-notes" tabindex="-1">Related Notes <a class="header-anchor" href="#related-notes" aria-label="Permalink to &quot;Related Notes&quot;">​</a></h2><ul><li><a href="/tech-log/">Tech Logs</a></li><li><a href="/career/long-term-roadmap.html">Long-Term Engineering Roadmap</a></li></ul>',11)])])}const p=a(i,[["render",l]]);export{u as __pageData,p as default};
